      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectsStore = {};

function getAllProjects() {
  return Object.values(projectsStore);
}

function getProjectById(projectId) {
  return projectsStore[projectId];
}

function createProject(name) {
  const projectId = randomUUID();
  const project = { id: projectId, name, members: [], tasks: [] };
  projectsStore[projectId] = project;
  return project;
}

module.exports = {
  getAllProjects,
  getProjectById,
  createProject,
};
