      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
taskService = require('./service');
commentsRoutes = require('../comments/routes');

const router = express.Router();

router.get('/', (req, res) => {
  const { status } = req.query;
  const tasks = taskService.getTasksByProjectId(req.projectId);
  if (status) {
    return res.json({ tasks: tasks.filter(task => task.status === status) });
  }
  res.json({ tasks });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  const task = taskService.createTask(req.projectId, name);
  res.status(201).json({ task });
});

router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be todo or done');
  }
  const task = taskService.updateTask(req.projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

router.use('/:taskId/comments', (req, res, next) => {
  req.taskId = req.params.taskId;
  next();
}, commentsRoutes);

module.exports = router;
