      "path": "src/modules/tasks/service.js",
      "content": "const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

function getTasksByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return [];
  }
  return project.tasks;
}

function createTask(projectId, name) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  const taskId = randomUUID();
  const task = { id: taskId, name, status: 'todo' };
  project.tasks.push(task);
  return task;
}

function updateTask(projectId, taskId, status) {
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
}

module.exports = {
  getTasksByProjectId,
  createTask,
  updateTask,
};
